from source import next_palindrome

def test_odd_length_non_nine_center_returns_incremented_palindrome():
    result = next_palindrome([1, 4, 3, 4, 1])
    assert isinstance(result, list), (
        f"next_palindrome([1,4,3,4,1]) returned {result!r} (None) instead of a list; "
        "return digit_list is unreachable when low_mid == high_mid"
    )
    assert result == [1, 4, 4, 4, 1], (
        f"Expected [1,4,4,4,1] but got {result!r}"
    )
